def is_invertible_mod(a, n):
    """Check if 'a' is invertible modulo 'n'."""
    try:
        # Compute modular inverse using extended Euclidean algorithm
        g, x, y = extended_gcd(a, n)
        if g != 1:
            return False  # No inverse exists
        else:
            return True
    except ValueError:
        return False

def extended_gcd(a, b):
    """Extended Euclidean algorithm to find gcd and coefficients."""
    if a == 0:
        return (b, 0, 1)
    else:
        g, y, x = extended_gcd(b % a, a)
        return (g, x - (b // a) * y, y)

# Example usage:
print(is_invertible_mod(5, 6))  # True (5 is invertible mod 6)
print(is_invertible_mod(2, 4))  # False (2 is not invertible mod 4)
